exercises.snippet:
def greedy_coins(amount, coins):
    coins = sorted(coins, reverse=True)
    used = []
    for coin in coins:
        while amount >= coin:
            amount -= coin
            used.append(coin)
    return used

print(greedy_coins(63, [25, 10, 5, 1]))

